         => __( 'All Categories', 'consen' ),		'parent_item'       => __( 'Parent Category', 'consen' ),		'parent_item_colon' => __( 'Parent Category:', 'consen' ),		'edit_item'         => __( 'Edit Category', 'consen' ),		'update_item'       => __( 'Update Category', 'consen' ),		'add_new_item'      => __( 'Add New Category', 'consen' ),		'new_item_name'     => __( 'New Category Name', 'consen' ),		'menu_name'         => __( 'Categories', 'consen' ),	);	$args = array(		'public'            => false,		'hierarchical'      => true,		'labels'            => $labels,		'show_ui'           => true,		'show_admin_column' => true,		'show_in_nav_menus' => false,		'query_var'         => false,		'rewrite'           => array( 'slug' => 'portfolio-category' ),	);		register_taxonomy( 'em_portfolio_cat', array( 'em_portfolio' ), $args );}add_action('init', 'consen_portfolio_post_type');// Case Studyfunction consen_case_study_post_type() {	$labels = array(		'name'               => _x( 'Case Study', 'post type general name', 'consen' ),		'singular_name'      => _x( 'Case Study', 'post type singular name', 'consen' ),		'menu_name'          => _x( 'Case Study', 'admin menu', 'consen' ),		'name_admin_bar'     => _x( 'Case Study', 'add new on admin bar', 'consen' ),		'add_new'            => _x( 'Add New', 'Case Study', 'consen' ),		'add_new_item'       => __( 'Add New Case Study', 'consen' ),		'new_item'           => __( 'New Case Study', 'consen' ),		'edit_item'          => __( 'Edit Case Study', 'consen' ),		'view_item'          => __( 'View Case Study', 'consen' ),		'all_items'          => __( 'All Case Study', 'consen' ),		'search_items'       => __( 'Search Case Study', 'consen' ),		'parent_item_colon'  => __( 'Parent Case Study:', 'consen' ),		'not_found'          => __( 'No Case Study found.', 'consen' ),		'not_found_in_trash' => __( 'No Case Study found in Trash.', 'consen' )	);		$args = array(		'labels'             => $labels,		'public'             => true,		'menu_icon'          =>'dashicons-format-status',				'exclude_from_search'=> true,		'show_ui'            => true,		'show_in_menu'       => true,		'query_var'          => true,		'rewrite'            => array( 'slug' => 'em_case_study' ),		'capability_type'    => 'post',		'has_archive'        => true,		'hierarchical'       => false,		'menu_position'      => null,		'supports'           => array('title','editor', 'thumbnail')	);		register_post_type( 'em_case_study' , $args );		$labels = array(		'name'              => _x( 'Categories', 'taxonomy general name', 'consen' ),		'singular_name'     => _x( 'Category', 'taxonomy singular name', 'consen' ),		'search_items'      => __( 'Search Categories', 'consen' ),		'all_items'         => __( 'All Categories', 'consen' ),		'parent_item'       => __( 'Parent Category', 'consen' ),		'parent_item_colon' => __( 'Parent Category:', 'consen' ),		'edit_item'         => __( 'Edit Category', 'consen' ),		'update_item'       => __( 'Update Category', 'consen' ),		'add_new_item'      => __( 'Add New Category', 'consen' ),		'new_item_name'     => __( 'New Category Name', 'consen' ),		'menu_name'         => __( 'Categories', 'consen' ),	);	$args = array(		'public'            => false,		'hierarchical'      => true,		'labels'            => $labels,		'show_ui'           => true,		'show_admin_column' => true,		'show_in_nav_menus' => false,		'query_var'         => false,		'rewrite'           => array( 'slug' => 'casestudy-category' ),	);		register_taxonomy( 'em_case_study_cat', array( 'em_case_study' ), $args );}add_action('init', 'consen_case_study_post_type');